export const meta={name:'pass7-verify',description:'Pass-7: 2-agent verify of 7 findings',phases:[{title:'Verify'}]}
const ROOT='/Users/[REDACTED]/hc-assay'
const F=[{"id": "J-001", "severity": "high", "file": "scripts/capture_transcripts.py", "line": "108-113", "title": "Strict UTF-8 decode in scrubber fails OPEN: one invalid byte routes the whole transcript to verbatim copy, re-leaking secrets/PII", "description": "VERIFIED. _copy_scrubbed() does `try: text = raw.decode('utf-8') except UnicodeDecodeError: data = raw`. A single invalid UTF-8 byte anywhere in a .jsonl/.json transcript raises UnicodeDecodeError and routes the ENTIRE file to the verbatim branch, copied byte-for-byte with no scrubbing. Claude tool-result transcripts routinely embed arbitrary subprocess stdout (hexdumps, latin-1/non-UTF-8 file reads, truncated multibyte from killed processes) inside JSONL string values, so this is a common condition. Pre-CV-O-1 the .jsonl path decoded with errors='replace' and was ALWAYS scrubbed; the CV-O-1 fix turned an always-redact path into a fail-open one precisely for the files most likely to carry raw dumped data. This is the new code being the defect \u2014 the highest-severity privacy guarantee (no operator email/username/path, no credential-shaped secret) now silently fails for affected files.", "poc": "src.write_bytes(b'{\"out\":\"[REDACTED] caf\\xe9byte=\\x80 /Users/[REDACTED]/x\"}'); raw=src.read_bytes(); try: data=_scrub(raw.decode('utf-8')).encode() except UnicodeDecodeError: data=raw  ->  b'[REDACTED]' in data == True (LEAKED), b'[REDACTED]' in data == True (LEAKED), b'REDACTED' in data == False. Under pre-CV-O-1 code the same file was decoded errors='replace' and fully scrubbed.", "suggested_fix": "Decode for scrubbing with errors='replace' (or 'backslashreplace'/'surrogatepass') so a stray byte never disables redaction: `text = raw.decode('utf-8', errors='replace'); data = _scrub(text).encode('utf-8')`. If a genuine binary verbatim path is still wanted, gate it on a real binary signal (`if b'\\x00' in raw: data = raw`) rather than on UTF-8 validity, since UTF-8-invalidity != binary. Add a regression test: a .jsonl containing a secret AND an invalid byte must come out scrubbed.", "dimension": "privacy / data-leak (fail-open regression)"}, {"id": "J-002", "severity": "high", "file": "scripts/capture_transcripts.py", "line": 38, "title": "Operator full display name ('Thomas Jones') is not scrubbed \u2014 leaks in 252 committed transcript files alongside redacted emails", "description": "VERIFIED. _SECRET_PATTERNS + _USERNAME_RE redact the operator's email and the bare home-dir username ('[REDACTED]'), and mask the username inside paths/slugs, but do NOT redact the operator's real full DISPLAY NAME ('Thomas Jones'), which is distinct operator PII appearing via git author strings, pyproject authors=[], and prose. Confirmed live and already committed: `grep -rc 'Thomas Jones' transcripts/` returns 252 files with the name in cleartext, frequently directly beside a successfully-redacted email (e.g. `Author: Thomas Jones <[REDACTED]>`). `git log -1 --format=%an` returns 'Thomas Jones', confirming this is the operator identity, not a coincidental token. De-identifying the email while leaving the adjacent full name defeats the de-identification purpose of the #F-024/#G-007 work. No test in tests/test_scripts.py covers full-name redaction (0 matches), confirming an unintentional gap rather than a documented scope decision.", "poc": "1) cd /Users/[REDACTED]/hc-assay  2) git log -1 --format='%an' -> 'Thomas Jones' (operator PII)  3) grep -rc 'Thomas Jones' transcripts/ -> 252 files with count >=1 (cleartext)  4) _scrub('Author: Thomas Jones <a@b.c>') -> 'Author: Thomas Jones <[REDACTED]>' (email masked, full name leaks).", "suggested_fix": "Derive the operator display name (from `git config user.name` and/or a configurable ASSAY_SCRUB_NAMES env list) and add it to the redaction set, mirroring _username_pattern(): re.escape'd, word-boundaried, length-guarded, applied in _scrub() (skip if empty/too-short to avoid over-redacting common words). Add a test_scripts.py case asserting _scrub('Author: Thomas Jones <a@b.c>') masks BOTH name and email. Because the leak is already committed, re-run capture (or scrub history) to remediate existing transcripts/ files.", "dimension": "privacy / operator PII (coverage gap, CV-O-1 class)"}, {"id": "J-003", "severity": "medium", "file": ".github/workflows/ci.yml", "line": 35, "title": "Build backend (hatchling) fetched live and un-hashed during `pip install -e .`, defeating the hash-pin/reproducibility guarantee", "description": "VERIFIED. All three jobs install with `pip install --no-deps -e .` (lines 35, 80, 191). `--no-deps` suppresses runtime deps but does NOT disable PEP 517 build isolation. pyproject.toml declares `build-system.requires = ['hatchling']` and uses hatchling.build (confirmed), and version is dynamic, so pip creates an isolated build env and fetches hatchling + its deps (editables, trove-classifiers) LIVE from PyPI, un-pinned and un-hashed, every CI run. Neither lockfile contains hatchling (`grep -ic '^hatchling==' requirements.lock requirements-core.lock` -> 0/0; 0 matches for any 'hatchling'). Consequences: (1) the workflow's central claim of installing 'EXACTLY the versions pip-audit scanned' is false for the build toolchain; (2) pip-audit (-r requirements.lock) never sees hatchling, so a compromised hatchling/editables patch executes arbitrary code during the editable build yet is never scanned \u2014 the exact #F-004 window the comments claim closed; (3) the SBOM omits the build-time dep set; (4) a yanked/changed hatchling makes a green commit non-reproducible.", "poc": "grep -ic '^hatchling==' requirements.lock requirements-core.lock -> 0 and 0, while the package still builds via hatchling.build. On a clean runner `pip install --no-deps -e .` emits 'Installing build dependencies: hatchling, editables, ...' resolved live from PyPI with no --require-hashes and no lock entry.", "suggested_fix": "Include the build backend in the hashed set and disable live build isolation in CI: (a) add hatchling to a build/dev group, regenerate locks with --generate-hashes, and install with `pip install --no-build-isolation --no-deps -e .` so the hashed hatchling is used; or (b) build a wheel in a separately-pinned hashed build env and pip-install that wheel. Extend SBOM/pip-audit coverage to the build toolchain.", "dimension": "supply chain / reproducibility"}, {"id": "J-004", "severity": "medium", "file": "src/assay_engine/observability/tracking.py", "line": 64, "title": "Check-then-create TOCTOU in _experiment_id loses the whole MLflow run under concurrent first-time start_run", "description": "VERIFIED. _experiment_id() does get_experiment_by_name() then, if None, create_experiment() \u2014 a classic TOCTOU (lines 64-68). The first time a given experiment name is used, two concurrent start_run() calls can both see None and both call create_experiment(); MLflow rejects the loser with MlflowException(RESOURCE_ALREADY_EXISTS), which propagates out of _experiment_id -> start_run. Reachable under the engine's own concurrency model: the reasoning seam runs an 8-thread pool, and multiple study processes legitimately share one local store. The consequence is exactly the lifecycle failure the rest of the module is engineered to avoid: in run_study a start_run exception leaves run_id=None, after which every track() call silently no-ops, dropping ALL metrics, the run_duration SLO metric, and provenance-trail artifact correlation for that entire study \u2014 and no MLflow run exists. The module's #F-023 orphan-termination logic targets phantom runs, but the experiment-creation step itself is unguarded, and no test covers the duplicate-create path.", "poc": "Two threads call tracker.start_run('r', {}) for a brand-new experiment name (get_experiment_by_name == None for both); both enter create_experiment, one raises MlflowException(RESOURCE_ALREADY_EXISTS). In run_study this surfaces as run_id=None -> all metrics for the study silently dropped.", "suggested_fix": "Make resolution race-tolerant: wrap create_experiment in try/except that, on the duplicate-name error (RESOURCE_ALREADY_EXISTS, or any failure), re-fetches via get_experiment_by_name(self._experiment) and returns its experiment_id; re-raise only if the re-fetch still returns None. Mirrors mlflow.set_experiment's get-or-create idiom. Add a test simulating create_experiment raising already-exists and asserting fallback.", "dimension": "concurrency / observability data loss"}, {"id": "J-005", "severity": "medium", "file": "tests/integration/test_reasoning_drain.py", "line": "143-146, 168-171, 202-206", "title": "T3 transient error-classification tests are non-discriminating: assert base ReasoningError, so a transient->permanent/rate-limit misclassification still passes", "description": "VERIFIED. The T3 drain classifier's purpose is to map an SDK error to the CORRECT subtype because the retry executor branches on exact subtype (PermanentReasoningError => no retry; RateLimitError => long backpressure; base ReasoningError => fast backoff). Both subtypes subclass ReasoningError. Three drain tests assert classification only via pytest.raises(ReasoningError) (the base class): test_t3_empty_reply_raises_transient (145), test_t3_generic_error_maps_to_transient (a 500, 170), test_t3_sdk_raises_mid_stream_maps_to_transient (205). Since pytest.raises catches subclasses, these pass even if the code misclassifies \u2014 e.g. mapping a generic 500 to PermanentReasoningError (don't retry) or RateLimitError still satisfies the assertion. The transient-vs-permanent distinction these tests claim to guard is exactly what is NOT asserted. By contrast, the same file's specific tests correctly pin subtypes (test_t3_auth_error_maps_to_permanent:164 -> PermanentReasoningError; test_t3_overloaded_529_maps_to_ratelimit:182 -> RateLimitError), confirming an isolated weakness, not a convention.", "poc": "In seam.py replace the generic fall-through `raise ReasoningError(...)` with `raise PermanentReasoningError(...)` (a real misclassification: a transient 500 becomes non-retryable). Re-run test_t3_generic_error_maps_to_transient \u2014 it still PASSES because PermanentReasoningError subclasses ReasoningError; the test fails to detect the 500 is no longer retried.", "suggested_fix": "Make the transient assertions discriminating: capture the exception and assert it is exactly the base/transient type and not the specific subtypes, e.g. `with pytest.raises(ReasoningError) as ei: _run(); assert type(ei.value) is ReasoningError; assert not isinstance(ei.value, (PermanentReasoningError, RateLimitError))` (or introduce a dedicated TransientReasoningError and assert it). Apply to all three tests so a transient->permanent/rate-limit regression fails every run.", "dimension": "test quality / non-discriminating assertion"}, {"id": "J-006", "severity": "low", "file": ".github/workflows/ci.yml", "line": 193, "title": "License gate scans entire site-packages (--with-system), not the hash-pinned set the comment claims", "description": "VERIFIED. The license-gate comment asserts it scans 'the SAME hash-pinned set pip-audit audited.' In practice the command is `pip-licenses --format=json --with-system` (line 193), enumerating EVERY distribution in site-packages. By that point the env also contains pip-licenses==5.5.5 and its transitive deps (prettytable, wcwidth), plus pip/setuptools/wheel via --with-system, plus the live-fetched build backend. So the license-checked set is a superset of requirements.lock, contradicting the comment and coupling the production-distribution license verdict to dev/tooling packages \u2014 a copyleft license in a tool dep would spuriously fail the gate. Additionally pip-licenses==5.5.5 is version-pinned but installed without --require-hashes (line 192), unlike every other install in the job \u2014 a minor pinning inconsistency.", "poc": "`pip-licenses --with-system` output set != requirements.lock package set; it includes pip-licenses, prettytable, wcwidth, pip, setuptools, wheel, and the build backend, none of which are in requirements.lock.", "suggested_fix": "Scan only the pinned distribution set: run pip-licenses without --with-system against the locked env, or drive it from requirements.lock package names. Install pip-licenses in a separate step/venv so tooling deps never enter the scanned environment, and add --require-hashes for the pip-licenses install to match the rest of the job.", "dimension": "supply chain / license-gate scope"}, {"id": "J-007", "severity": "low", "file": "scripts/capture_transcripts.py", "line": "118-119, 151-166", "title": "MANIFEST.json file paths and active_session are written without passing through _scrub", "description": "VERIFIED. main() writes transcripts/MANIFEST.json via json.dumps() with no scrubbing; each entry's 'path' is str(dstf.relative_to(...)) (line 119) and the top-level 'active_session' is the session stem (line 158), derived from source filenames. Today all captured filenames are opaque UUID/agent-id stems with no PII, so nothing leaks in practice \u2014 hence LOW. But it is the same structural class as CV-O-1: a committed artifact (the manifest) that bypasses the redaction path entirely. If any future transcript file in the session subtree is ever named with operator-identifying content (a path/slug/username in a filename), that PII would be copied verbatim into MANIFEST.json. File CONTENT is scrubbed; the manifest of paths is not.", "poc": "Inspect main(): the dict (captured[].path + active_session) is serialized with json.dumps() and written to MANIFEST without any _scrub() call; _copy_scrubbed scrubs file content but returns the raw relative path string for the manifest.", "suggested_fix": "Run the manifest's string fields through _scrub() before writing (scrub each rec['path'] and 'active_session', or _scrub the json.dumps blob before write_text). Cheap defense-in-depth that closes the structural gap for future filename shapes.", "dimension": "privacy / artifact-bypass (defense-in-depth)"}]
const V={type:'object',required:['finding_id','confirmed','reasoning','severity_assessment'],properties:{finding_id:{type:'string'},confirmed:{type:'boolean'},reasoning:{type:'string'},severity_assessment:{type:'string',enum:['critical','high','medium','low','false_positive']}}}
const vp=(f,n)=>`You are verifier #${n}, independent. Read the ACTUAL code at ${ROOT} and decide if this is a TRUE production-readiness problem in current code (6 passes hardened). confirmed=true only if real, reproducible, worth fixing (not speculative/by-design).\n${f.id}: ${f.title}\nFile: ${f.file}:${f.line}\n${f.description}\nPoC: ${f.poc}\nFix: ${f.suggested_fix}`
phase('Verify')
const r=await pipeline(F,f=>parallel([()=>agent(vp(f,1),{label:'vA:'+f.id,phase:'Verify',schema:V}),()=>agent(vp(f,2),{label:'vB:'+f.id,phase:'Verify',schema:V})]),
  (vs,f)=>{const[a,b]=vs.filter(Boolean);const both=a&&b&&a.confirmed&&b.confirmed;const neither=(!a||!a.confirmed)&&(!b||!b.confirmed);
    return{id:f.id,severity:f.severity,file:f.file,line:f.line,title:f.title,description:f.description,poc:f.poc,suggested_fix:f.suggested_fix,both_confirmed:both,neither_confirmed:neither,split:!both&&!neither,a:a?{c:a.confirmed,s:a.severity_assessment}:null,b:b?{c:b.confirmed,s:b.severity_assessment}:null}})
const c=r.filter(x=>x.both_confirmed),rej=r.filter(x=>x.neither_confirmed),sp=r.filter(x=>x.split)
log('confirmed='+c.length+' rejected='+rej.length+' split='+sp.length)
return{confirmed:c,rejected:rej,split:sp,all:r}
